// const does NOT make objects immutable
const user = { name: 'Alice' };
user.name = 'Bob'; // ✅ this works!
// user = {};       // ❌ TypeError — can't reassign const

// Object.freeze — shallow immutability
const config = Object.freeze({ theme: 'dark', nested: { lang: 'en' } });
// config.theme = 'light';      // silently fails (or throws in strict)
// config.newProp = 'x';        // silently fails
console.log(config.theme);      // 'dark' — unchanged
config.nested.lang = 'fr';      // ✅ nested NOT frozen!

// Object.seal
const sealed = Object.seal({ x: 1 });
sealed.x = 99;     // ✅ can change existing
// sealed.y = 2;   // ❌ can't add
// delete sealed.x; // ❌ can't remove

// Deep clone (modern)
const original = { a: 1, b: { c: 2 } };
const clone = structuredClone(original);
clone.b.c = 99;
console.log(original.b.c); // 2 — not affected
